     3→import { useState, useEffect, useCallback } from "react";
     4→import { useAuth } from "@/providers/auth-provider";
     5→import { createClient } from "@/lib/supabase/client";
     6→import type { Profile, ProfileUpdate } from "@/lib/types/profile";
     7→
     8→export function useProfile() {
     9→  const { user } = useAuth();
    10→  const [profile, setProfile] = useState<Profile | null>(null);
    11→  const [isLoading, setIsLoading] = useState(true);
    12→  const supabase = createClient();
    13→
    14→  useEffect(() => {
    15→    if (!user) {
    16→      setProfile(null);
    17→      setIsLoading(false);
    18→      return;
    19→    }
    20→
    21→    let cancelled = false;
    22→
    23→    const fetchProfile = async () => {
    24→      setIsLoading(true);
    25→      try {
    26→        const { data, error } = await supabase
    27→          .from("profiles")
    28→          .select("*")
    29→          .eq("id", user.id)
    30→          .single();
    31→
    32→        if (!cancelled) {
    33→          if (error && error.code !== "PGRST116") {
    34→            console.error("Profile fetch error:", error);
    35→          }
    36→          setProfile(data ?? null);
    37→        }
    38→      } catch (err) {
    39→        console.error("Profile fetch exception:", err);
    40→      } finally {
    41→        if (!cancelled) setIsLoading(false);
    42→      }
    43→    };
    44→
    45→    fetchProfile();
    46→    return () => { cancelled = true; };
    47→  }, [user, supabase]);
    48→
    49→  const createProfile = useCallback(
    50→    async (profileData: ProfileUpdate) => {
    51→      if (!user) throw new Error("Not authenticated");
    52→      const { data, error } = await supabase
    53→        .from("profiles")
    54→        .insert({ id: user.id, ...profileData })
    55→        .select()
    56→        .single();
    57→      if (error) throw error;
    58→      setProfile(data);
    59→      return data;
    60→    },
    61→    [user, supabase]
    62→  );
    63→
    64→  const updateProfile = useCallback(
    65→    async (updates: Partial<ProfileUpdate>) => {
    66→      if (!user) throw new Error("Not authenticated");
    67→      const { data, error } = await supabase
    68→        .from("profiles")
    69→        .update(updates)
    70→        .eq("id", user.id)
    71→        .select()
    72→        .single();
    73→      if (error) throw error;
    74→      setProfile(data);
    75→      return data;
    76→    },
    77→    [user, supabase]
    78→  );
    79→
    80→  return { profile, isLoading, createProfile, updateProfile };
    81→}
    82→

