import { cn } from "@/lib/utils";

const DECISION_STYLES: Record<string, { bg: string; text: string; border: string }> = {
  GO: { bg: "bg-emerald-500/10", text: "text-emerald-400", border: "border-emerald-500/20" },
  EXPLORE: { bg: "bg-amber-500/10", text: "text-amber-400", border: "border-amber-500/20" },
  PARK: { bg: "bg-gray-500/10", text: "text-gray-400", border: "border-gray-500/20" },
  KILL: { bg: "bg-red-500/10", text: "text-red-400", border: "border-red-500/20" },
};

interface DecisionBadgeProps {
  decision: string;
  className?: string;
  style?: React.CSSProperties;
}

export function DecisionBadge({ decision, className, style }: DecisionBadgeProps) {
  const badgeStyle = DECISION_STYLES[decision] ?? DECISION_STYLES.PARK;
  return (
    <div
      className={cn("px-4 py-1.5 rounded-full border font-bold text-xs tracking-widest uppercase", badgeStyle.bg, badgeStyle.text, badgeStyle.border, className)}
      style={style}
    >
      {decision}
    </div>
  );
}

