import { cn } from "@/lib/utils";
import { AlertTriangle } from "lucide-react";

interface AxisScoreBarProps {
  label: string;
  score: number;
  blockingGap?: boolean;
  className?: string;
}

function getBarColor(score: number): string {
  if (score >= 70) return "bg-emerald-500";
  if (score >= 50) return "bg-amber-500";
  if (score >= 30) return "bg-orange-500";
  return "bg-red-500";
}

export function AxisScoreBar({ label, score, blockingGap, className }: AxisScoreBarProps) {
  return (
    <div className={cn("flex items-center gap-3", className)}>
      <span className="text-xs text-gray-400 uppercase tracking-wider font-medium w-32 shrink-0 truncate">
        {label}
      </span>
      <div className="flex-1 h-2 bg-[#3A3D45] rounded-full overflow-hidden">
        <div
          className={cn("h-full rounded-full transition-all duration-700 ease-out", getBarColor(score))}
          style={{ width: `${score}%` }}
        />
      </div>
      <span className={cn(
        "text-sm font-mono w-10 text-right tabular-nums",
        score >= 70 ? "text-white" : "text-gray-400"
      )}>
        {score}
      </span>
      {blockingGap && (
        <span title="Blocking gap"><AlertTriangle className="w-4 h-4 text-red-400 shrink-0" /></span>
      )}
    </div>
  );
}

