"use client";

import { useEffect, useState, useMemo } from "react";
import { useRouter } from "next/navigation";
import { Archive } from "lucide-react";
import { SiteHeader } from "@/components/layout/site-header";
import { ProCard } from "@/components/workspace/pro-card";
import { FloatingDock } from "@/components/workspace/floating-dock";
import { ProjectDetailOverlay } from "@/components/workspace/project-detail-overlay";
import { useAuth } from "@/providers/auth-provider";
import { useProfile } from "@/hooks/use-profile";
import { useLanguageStore } from "@/store/language-store";
import { cn } from "@/lib/utils";
import { toast } from "sonner";

interface Project {
    id: string;
    title?: string;
    text: string;
    description?: string;
    color?: string;
    globalScore?: number;
    recommendation?: string;
    confidenceLevel?: string;
    viabilityScore?: number;
    classification?: string;
    timestamp: string;
    isDemo?: boolean;
    isArchived?: boolean;
    analysis?: any;
}

function getProjectDecision(p: Project): string {
    return p.recommendation ?? p.classification ?? "DRAFT";
}

function getProjectTitle(p: Project): string {
    return p.title ?? p.text;
}

export default function WorkspacePage() {
    const router = useRouter();
    const { user } = useAuth();
    const { profile } = useProfile();
    const { t } = useLanguageStore();

    const [projects, setProjects] = useState<Project[]>([]);
    const [searchQuery, setSearchQuery] = useState("");
    const [activeFilter, setActiveFilter] = useState<string>("ALL");
    const [sortBy, setSortBy] = useState<string>("date");
    const [showArchived, setShowArchived] = useState(false);

    // Detail overlay state
    const [detailProject, setDetailProject] = useState<Project | null>(null);
    const [detailOpen, setDetailOpen] = useState(false);

    // Initial Load Logic
    useEffect(() => {
        const currentIdea = localStorage.getItem("k3rn_active_project");
        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");

        if (currentIdea) {
            const idea = JSON.parse(currentIdea);
            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
            if (!exists) {
                const newProject: Project = {
                    id: idea.id || crypto.randomUUID(),
                    title: idea.title,
                    text: idea.text || "",
                    description: idea.description,
                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
                    recommendation: idea.recommendation ?? idea.analysis?.classification,
                    confidenceLevel: idea.confidenceLevel,
                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
                    classification: idea.classification ?? idea.analysis?.classification,
                    timestamp: idea.timestamp,
                    isDemo: idea.isDemo,
                    analysis: idea.analysis,
                };
                storedProjects.unshift(newProject);
                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
                localStorage.removeItem("k3rn_active_project");
            }
        }

        if (storedProjects.length === 0) {
            const mocks: Project[] = [
                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 92, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date().toISOString(), isDemo: true, description: "A comprehensive solution for autonomous drone logistics, featuring real-time telemetry, AI-driven pathfinding, and predictive maintenance.", analysis: { axes: [{ label: "Probleme", score: 9 }, { label: "Marche", score: 8 }, { label: "Differenciation", score: 10 }, { label: "Faisabilite", score: 8 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 9 }], synthesis: "Ce projet presente un potentiel exceptionnel. Le marche de la logistique drone est en pleine expansion avec un CAGR de 28%. La differenciation technique est maximale grace a l'integration d'IA pour le pathfinding et la maintenance predictive. Le business model SaaS assure des revenus recurrents. Recommandation : accelerer le developpement du MVP et securiser un premier contrat pilote.", risks: ["Reglementation aerienne complexe et en evolution — risque de delais reglementaires", "Cout d'infrastructure eleve pour le deploiement initial (stations de charge, communication)", "Competition potentielle des geants tech (Amazon Prime Air, Wing/Alphabet)", "Dependance aux conditions meteorologiques pour les operations quotidiennes"] } },
                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true, description: "Attempting to tokenize IP rights on the blockchain. Initial market validation suggests low demand.", analysis: { synthesis: "Le concept de tokenisation des brevets sur blockchain ne repond pas a un besoin reel du marche. Les acteurs industriels privilegient les canaux traditionnels de gestion de PI.", risks: ["Absence de demande marche validee", "Complexite juridique de la tokenisation de PI", "Modele economique non viable a long terme"] } },
                { id: "3", title: "AI Film Script Generator", text: "IA generative pour scripts de films", globalScore: 78, recommendation: "EXPLORE", confidenceLevel: "MEDIUM", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true, description: "Leveraging LLMs for creative writing assistance. The prototype shows promise but lacks structure.", analysis: { synthesis: "L'outil montre un potentiel creatif interessant mais necessite une structuration plus poussee du workflow narratif. Le marche de l'IA creative est en croissance rapide.", risks: ["Qualite narrative encore insuffisante pour un usage professionnel", "Concurrence forte des outils existants (ChatGPT, Jasper)", "Questions ethiques sur la propriete intellectuelle generee par IA"] } },
                { id: "4", title: "MeowNet - Social Network for Cats", text: "Reseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", confidenceLevel: "LOW", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true, description: "Niche social network. Market size is questionable despite high engagement potential." },
                { id: "5", title: "Quantum Encryption Key", text: "Cle de chiffrement quantique", globalScore: 88, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era.", analysis: { axes: [{ label: "Probleme", score: 10 }, { label: "Marche", score: 9 }, { label: "Differenciation", score: 8 }, { label: "Faisabilite", score: 7 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 8 }], synthesis: "Infrastructure de securite critique pour l'ere post-quantique. Le marche fintech est pret pour cette transition. La faisabilite technique est le principal defi.", risks: ["Complexite technique de l'implementation quantique", "Cout de R&D eleve avant commercialisation", "Risque de timing — marche pas encore pret massivement"] } },
            ];
            setProjects(mocks);
        } else {
            setProjects(storedProjects);
        }
    }, []);

    const filteredProjects = useMemo(() => {
        let result = projects.filter((p) => {
            // Filter by archived status
            const matchesArchiveStatus = showArchived ? p.isArchived === true : p.isArchived !== true;

            const q = searchQuery.toLowerCase();
            const matchesSearch =
                getProjectTitle(p).toLowerCase().includes(q) ||
                p.text.toLowerCase().includes(q) ||
                getProjectDecision(p).toLowerCase().includes(q);

            const matchesFilter = activeFilter === "ALL" || getProjectDecision(p) === activeFilter;

            return matchesArchiveStatus && matchesSearch && matchesFilter;
        });

        if (sortBy === "score") {
            result = [...result].sort((a, b) => (b.globalScore ?? 0) - (a.globalScore ?? 0));
        } else {
            result = [...result].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
        }

        return result;
    }, [projects, searchQuery, activeFilter, sortBy, showArchived]);

    // Welcome hero stats
    const goCount = projects.filter((p) => getProjectDecision(p) === "GO").length;
    const attentionCount = projects.filter((p) => {
        const d = getProjectDecision(p);
        return d === "EXPLORE" || d === "KILL";
    }).length;

    // Save handler for detail overlay
    function handleSaveProject(id: string, updates: { title?: string; description?: string }) {
        const updated = projects.map((p) =>
            p.id === id ? { ...p, ...updates } : p
        );
        setProjects(updated);
        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
        // Update detailProject so the overlay reflects saved data
        if (detailProject && detailProject.id === id) {
            setDetailProject({ ...detailProject, ...updates });
        }
        toast.success("Dossier sauvegardé");
    }

    // Archive handler
    function handleArchive(id: string) {
        const updated = projects.map((p) =>
            p.id === id ? { ...p, isArchived: true } : p
        );
        setProjects(updated);
        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
        setDetailOpen(false);
        setDetailProject(null);
    }

    // Unarchive handler
    function handleUnarchive(id: string) {
        const updated = projects.map((p) =>
            p.id === id ? { ...p, isArchived: false } : p
        );
        setProjects(updated);
        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
        setDetailOpen(false);
        setDetailProject(null);
    }

    // Delete handler
    function handleDelete(id: string) {
        const updated = projects.filter((p) => p.id !== id);
        setProjects(updated);
        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
        setDetailOpen(false);
        setDetailProject(null);
    }

    // Item size state with persistence
    const [itemSize, setItemSize] = useState(360);
    const [isLoaded, setIsLoaded] = useState(false);

    useEffect(() => {
        const savedSize = localStorage.getItem("k3rn_card_size");
        if (savedSize) {
            setItemSize(Number(savedSize));
        }
        setIsLoaded(true);
    }, []);

    useEffect(() => {
        if (isLoaded) {
            localStorage.setItem("k3rn_card_size", itemSize.toString());
        }
    }, [itemSize, isLoaded]);

    return (
        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
            <SiteHeader variant="app" />

            <main className="relative z-[1] flex-1 pt-24 pb-40 px-8 w-full max-w-[1400px] mx-auto">

                {/* Welcome Hero */}
                <div
                    className="mb-12 rounded-[var(--radius-2xl)] p-8 animate-in fade-in slide-in-from-bottom-4 duration-500"
                    style={{
                        background: "var(--color-bg-secondary)",
                        border: "1px solid var(--color-border-subtle)",
                    }}
                >
                    <h1 className="text-[2.5rem] font-light text-white tracking-[-0.02em] leading-[1.1] mb-3">
                        Bonjour, <span className="text-white">{user?.user_metadata?.full_name?.split(' ')[0] || user?.user_metadata?.full_name || "l'ami"}</span>.
                    </h1>
                    <div className="flex items-center justify-between">
                        <p className="text-base text-[--color-text-muted] flex items-center gap-2">
                            <strong className="text-[--color-text-secondary] font-medium">{projects.filter(p => !p.isArchived).length}</strong> dossier{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""} actif{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""}
                            {" "}&middot;{" "}
                            <strong className="text-[--color-text-secondary] font-medium">{goCount}</strong> projet{goCount !== 1 ? "s" : ""} valide{goCount !== 1 ? "s" : ""} GO
                            {" "}&middot;{" "}
                            <strong className="text-[--color-text-secondary] font-medium">{attentionCount}</strong> necessite{attentionCount !== 1 ? "nt" : ""} votre attention
                        </p>
                        <button
                            onClick={() => setShowArchived(!showArchived)}
                            className="group inline-flex items-center gap-2 px-4 py-2 bg-transparent text-[--color-text-muted] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-300 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong] hover:scale-[1.02] active:scale-[0.98]"
                        >
                            <Archive className="w-4 h-4 transition-transform duration-300 group-hover:scale-110" />
                            {showArchived ? "Dossiers actifs" : "Dossiers archivés disponibles"}
                        </button>
                    </div>
                </div>

                {/* Grid */}
                <div className={cn(
                    "animate-in fade-in zoom-in-95 duration-500",
                    "grid gap-6"
                )}
                    style={{ gridTemplateColumns: `repeat(auto-fill, minmax(${itemSize}px, 1fr))` }}
                >
                    {/* New Project Card - Only show when NOT in archived view */}
                    {!showArchived && (
                        <ProCard
                            isNew
                            size={itemSize}
                            onClick={() => router.push('/capture')}
                        />
                    )}

                    {/* Project Cards */}
                    {filteredProjects.map((project) => (
                        <ProCard
                            key={project.id}
                            project={project}
                            size={itemSize}
                            onClick={() => {
                                setDetailProject(project);
                                setDetailOpen(true);
                            }}
                        />
                    ))}
                </div>
            </main>

            {/* Floating Command Dock */}
            <FloatingDock
                searchQuery={searchQuery}
                setSearchQuery={setSearchQuery}
                activeFilter={activeFilter}
                setActiveFilter={setActiveFilter}
                sortBy={sortBy}
                setSortBy={setSortBy}
                itemSize={itemSize}
                setItemSize={setItemSize}
                onNewProject={() => router.push('/capture')}
            />

            {/* Project Detail Overlay */}
            <ProjectDetailOverlay
                project={detailProject}
                open={detailOpen}
                onClose={() => {
                    setDetailOpen(false);
                    setDetailProject(null);
                }}
                onSave={handleSaveProject}
                onArchive={handleArchive}
                onUnarchive={handleUnarchive}
                onDelete={handleDelete}
            />
        </div>
    );
}

