/**
 * K3RN.LABS — POST /api/expert-chat
 * Chat expert contextuel via Claude API avec streaming SSE
 */

import Anthropic from "@anthropic-ai/sdk";

const anthropic = new Anthropic({
    apiKey: process.env.ANTHROPIC_API_KEY,
});

const CHAT_MODEL = process.env.EXPERT_CHAT_MODEL || "claude-sonnet-4-20250514";

interface ChatMessage {
    role: "user" | "assistant";
    content: string;
}

interface ChatRequest {
    messages: ChatMessage[];
    projectContext: {
        title: string;
        description: string;
        globalScore: number;
        recommendation: string;
        confidenceLevel: string;
        axes: Array<{ label: string; score: number; justification?: string }>;
        synthesis: string;
        risks: string[];
        levers?: Array<{ axis: string; action: string; expected_impact: string }>;
    };
    labType: "discovery" | "structuration";
    language: string;
}

function buildSystemPrompt(req: ChatRequest): string {
    const { projectContext, labType, language } = req;
    const lang = language === "FR" ? "français" : language === "ES" ? "español" : "English";

    const projectBlock = `
## Projet analysé
- **Titre** : ${projectContext.title}
- **Description** : ${projectContext.description}
- **Score global** : ${projectContext.globalScore}/100
- **Recommandation** : ${projectContext.recommendation}
- **Confiance** : ${projectContext.confidenceLevel}

### Axes d'analyse
${projectContext.axes.map((a) => `- **${a.label}** : ${a.score}/100${a.justification ? ` — ${a.justification}` : ""}`).join("\n")}

### Synthèse
${projectContext.synthesis}

### Risques identifiés
${projectContext.risks.length > 0 ? projectContext.risks.map((r) => `- ${r}`).join("\n") : "Aucun risque majeur identifié."}
${
    projectContext.levers && projectContext.levers.length > 0
        ? `\n### Leviers d'action\n${projectContext.levers.map((l) => `- [${l.expected_impact}] ${l.action} (axe: ${l.axis})`).join("\n")}`
        : ""
}`;

    if (labType === "discovery") {
        return `Tu es **Ava**, experte en Discovery et validation d'idées chez K3RN.LABS.

## Ta personnalité
- Socratique : tu poses des questions qui forcent la réflexion profonde
- Challengeuse : tu identifies les failles et angles morts sans complaisance
- Bienveillante mais directe : tu veux aider l'entrepreneur à voir clair

## Ton rôle dans le Lab Discovery
- Challenger les hypothèses non validées
- Mettre en lumière les axes faibles (score < 50) et les risques
- Poser des questions ouvertes qui poussent à l'investigation terrain
- Suggérer des expériences de validation rapides (interviews, landing pages, smoke tests)
- Ne JAMAIS donner de fausses assurances — si le projet a des failles, les nommer

## Règles
- Réponds en ${lang}
- Sois concise (2-4 paragraphes max sauf si la question demande plus)
- Utilise le contexte projet ci-dessous pour personnaliser chaque réponse
- Si l'utilisateur sort du sujet, ramène-le au projet

${projectBlock}`;
    }

    return `Tu es **Marcus**, expert en Structuration et stratégie business chez K3RN.LABS.

## Ta personnalité
- Pragmatique : tu penses en frameworks actionnables (BMC, Lean Canvas, OKR)
- Stratège : tu vois les leviers de croissance et les quick wins
- Orienté action : chaque conseil doit aboutir à un next step concret

## Ton rôle dans le Lab Structuration
- Aider à construire le Business Model Canvas
- Transformer les leviers d'action en plan concret avec milestones
- Capitaliser sur les forces (axes ≥ 70) pour définir l'avantage concurrentiel
- Proposer des métriques clés (KPI) pour chaque milestone
- Structurer la roadmap : MVP → Premiers Users → Revenue → Scale

## Règles
- Réponds en ${lang}
- Sois concis et actionnable (2-4 paragraphes max sauf si la question demande plus)
- Utilise le contexte projet ci-dessous pour personnaliser chaque réponse
- Si l'utilisateur sort du sujet, ramène-le à la structuration

${projectBlock}`;
}

export async function POST(req: Request) {
    try {
        const body: ChatRequest = await req.json();

        if (!body.messages || !Array.isArray(body.messages) || body.messages.length === 0) {
            return new Response(JSON.stringify({ error: "messages required" }), {
                status: 400,
                headers: { "Content-Type": "application/json" },
            });
        }

        const systemPrompt = buildSystemPrompt(body);

        const stream = anthropic.messages.stream({
            model: CHAT_MODEL,
            max_tokens: 1024,
            temperature: 0.7,
            system: systemPrompt,
            messages: body.messages.map((m) => ({
                role: m.role,
                content: m.content,
            })),
        });

        const encoder = new TextEncoder();

        const readable = new ReadableStream({
            async start(controller) {
                try {
                    for await (const event of stream) {
                        if (
                            event.type === "content_block_delta" &&
                            event.delta.type === "text_delta"
                        ) {
                            const data = JSON.stringify({ text: event.delta.text });
                            controller.enqueue(encoder.encode(`data: ${data}\n\n`));
                        }
                    }
                    controller.enqueue(encoder.encode("data: [DONE]\n\n"));
                    controller.close();
                } catch (error: any) {
                    const errorData = JSON.stringify({
                        error: error.status === 429 ? "rate_limited" : "stream_error",
                        message: error.message,
                    });
                    controller.enqueue(encoder.encode(`data: ${errorData}\n\n`));
                    controller.close();
                }
            },
        });

        return new Response(readable, {
            headers: {
                "Content-Type": "text/event-stream",
                "Cache-Control": "no-cache",
                Connection: "keep-alive",
            },
        });
    } catch (error: any) {
        if (error.status === 429) {
            return new Response(
                JSON.stringify({ error: "rate_limited", message: "Too many requests" }),
                { status: 429, headers: { "Content-Type": "application/json" } }
            );
        }
        return new Response(
            JSON.stringify({ error: "internal", message: error.message }),
            { status: 500, headers: { "Content-Type": "application/json" } }
        );
    }
}

