"use client";

import { AlertTriangle, Shield } from "lucide-react";
import { cn } from "@/lib/utils";
import { DecisionBadge } from "@/components/ui/decision-badge";
import { AxisScoreBar } from "@/components/ui/axis-score-bar";
import type { StoredProject } from "@/hooks/use-project";

interface DiscoveryPanelProps {
    project: StoredProject;
}

const AXIS_KEYS = ["problem", "market", "differentiation", "feasibility", "business", "founder_fit"] as const;

function getAxes(project: StoredProject) {
    // If fullResult exists, use it directly
    if (project.fullResult) {
        return AXIS_KEYS.map((key) => {
            const axis = project.fullResult!.analysis[key];
            return {
                key,
                label: key.charAt(0).toUpperCase() + key.slice(1).replace("_", " "),
                score: axis.score,
                blockingGap: axis.blocking_gap,
                justification: axis.justification,
            };
        });
    }

    // Fallback: use project.analysis.axes with normalization
    return project.analysis.axes.map((a) => ({
        key: a.label.toLowerCase().replace(/\s+/g, "_"),
        label: a.label,
        // Normalize: if scores are 0-10, multiply by 10
        score: a.score <= 10 ? a.score * 10 : a.score,
        blockingGap: false,
        justification: a.justification || "",
    }));
}

function getRisks(project: StoredProject) {
    if (project.fullResult) {
        return project.fullResult.risks;
    }
    return project.analysis.risks.map((r) => ({
        axis: "business" as const,
        description: r,
        severity: "MEDIUM" as const,
    }));
}

export function DiscoveryPanel({ project }: DiscoveryPanelProps) {
    const axes = getAxes(project);
    const risks = getRisks(project);
    const weakAxes = axes.filter((a) => a.score < 50);

    return (
        <aside className="w-72 bg-[#22242B] border-r border-[#3A3D45] flex flex-col shrink-0 overflow-y-auto">
            {/* Score + Decision */}
            <div className="p-5 border-b border-[#3A3D45]">
                <div className="flex items-center justify-between mb-3">
                    <div>
                        <span className="text-[10px] text-gray-500 uppercase tracking-widest font-bold">Score Global</span>
                        <div className={cn(
                            "text-4xl font-bold tracking-tight mt-1",
                            project.globalScore >= 70 ? "text-white" : "text-gray-400"
                        )}>
                            {project.globalScore}
                        </div>
                    </div>
                    <DecisionBadge decision={project.recommendation} />
                </div>
                <div className="text-[10px] text-gray-500 uppercase tracking-widest">
                    Confiance: {project.confidenceLevel}
                </div>
            </div>

            {/* 6 Axes */}
            <div className="p-5 border-b border-[#3A3D45]">
                <h3 className="text-[10px] text-gray-500 uppercase tracking-widest font-bold mb-4">
                    Axes d&apos;analyse
                </h3>
                <div className="space-y-3">
                    {axes.map((axis) => (
                        <div key={axis.key} className={cn(
                            "relative",
                            axis.score < 50 && "ring-1 ring-red-500/20 rounded-lg p-2 -mx-2 bg-red-500/5"
                        )}>
                            <AxisScoreBar
                                label={axis.label}
                                score={axis.score}
                                blockingGap={axis.blockingGap}
                            />
                        </div>
                    ))}
                </div>
                {weakAxes.length > 0 && (
                    <div className="mt-3 flex items-center gap-2 text-[10px] text-red-400">
                        <AlertTriangle className="w-3 h-3" />
                        <span>{weakAxes.length} axe{weakAxes.length > 1 ? "s" : ""} critique{weakAxes.length > 1 ? "s" : ""} (&lt;50)</span>
                    </div>
                )}
            </div>

            {/* Risks */}
            {risks.length > 0 && (
                <div className="p-5 border-b border-[#3A3D45]">
                    <h3 className="text-[10px] text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
                        <AlertTriangle className="w-3 h-3 text-red-400" />
                        Risques
                    </h3>
                    <div className="space-y-2">
                        {risks.map((risk, i) => (
                            <div key={i} className="flex items-start gap-2">
                                <span className={cn(
                                    "text-[9px] font-bold uppercase tracking-wider shrink-0 mt-0.5 px-1.5 py-0.5 rounded",
                                    risk.severity === "HIGH" ? "bg-red-500/10 text-red-400" :
                                    risk.severity === "MEDIUM" ? "bg-amber-500/10 text-amber-400" :
                                    "bg-gray-500/10 text-gray-400"
                                )}>
                                    {risk.severity}
                                </span>
                                <span className="text-xs text-gray-400 leading-relaxed">{risk.description}</span>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* KILL Warning */}
            {project.recommendation === "KILL" && (
                <div className="p-5 border-b border-[#3A3D45]">
                    <div className="flex items-start gap-3 p-3 rounded-lg bg-red-500/10 border border-red-500/20">
                        <Shield className="w-4 h-4 text-red-400 shrink-0 mt-0.5" />
                        <div className="text-xs text-red-300 leading-relaxed">
                            Ce projet a recu une recommandation <strong>KILL</strong>. L&apos;analyse suggere des failles fondamentales. Utilisez ce lab pour valider si un pivot est possible.
                        </div>
                    </div>
                </div>
            )}

            {/* Confidence */}
            <div className="p-5 mt-auto">
                <div className="flex items-center gap-2 text-[10px] text-gray-500">
                    <div className={cn(
                        "w-2 h-2 rounded-full",
                        project.confidenceLevel === "HIGH" ? "bg-emerald-500" :
                        project.confidenceLevel === "MEDIUM" ? "bg-amber-500" :
                        "bg-red-500"
                    )} />
                    Indice de confiance : {project.confidenceLevel}
                </div>
            </div>
        </aside>
    );
}

