            </div>
        </main>
    );
}

input.content:
"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { Settings, Send } from "lucide-react";
import { useLanguageStore } from "@/store/language-store";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import type { StoredProject } from "@/hooks/use-project";

interface ChatMessage {
    role: "user" | "assistant";
    content: string;
}

interface ExpertChatProps {
    projectId: string;
    project?: StoredProject | null;
    labType?: "discovery" | "structuration";
}

function getExpertInfo(labType: "discovery" | "structuration") {
    if (labType === "discovery") {
        return { name: "Ava", letter: "A", role: "Discovery Expert", color: "bg-[#F75105]", borderColor: "border-[#F75105]/30" };
    }
    return { name: "Marcus", letter: "M", role: "Strategy Expert", color: "bg-emerald-500", borderColor: "border-emerald-500/30" };
}

function getWelcomeMessage(project: StoredProject | null, labType: "discovery" | "structuration"): string {
    if (!project) return labType === "discovery"
        ? "Bonjour ! Je suis Ava, votre experte Discovery. Chargez un projet pour que je puisse vous aider a l'explorer."
        : "Bonjour ! Je suis Marcus, votre expert Structuration. Chargez un projet pour commencer a batir.";

    if (labType === "discovery") {
        const weakAxes = project.analysis.axes.filter((a) => {
            const score = a.score <= 10 ? a.score * 10 : a.score;
            return score < 60;
        });
        const weakList = weakAxes.map((a) => a.label).join(", ");
        return `Bonjour ! Je suis **Ava**, votre experte Discovery. J'ai analyse votre projet **"${project.title}"** — score global de **${project.globalScore}/100** (${project.recommendation}).${
            weakAxes.length > 0
                ? ` Je remarque des axes a approfondir : **${weakList}**. Commenccons par challenger vos hypotheses sur ces points.`
                : ` Le profil est solide. Explorons ensemble les angles morts potentiels.`
        } Quelle question souhaitez-vous explorer en premier ?`;
    }

    return `Bonjour ! Je suis **Marcus**, votre expert Structuration. Votre projet **"${project.title}"** a obtenu **${project.globalScore}/100** (${project.recommendation}). ${
        project.globalScore >= 70
            ? "C'est un signal fort — concentrons-nous sur la structuration de votre avantage competitif et votre go-to-market."
            : "Il y a du potentiel. Structurons les fondations pour renforcer le projet."
    } Par quoi voulez-vous commencer — Business Model, Plan d'Action, ou Roadmap ?`;
}

export function ExpertChat({ projectId, project = null, labType = "discovery" }: ExpertChatProps) {
    const { t, currentLang } = useLanguageStore();
    const expert = getExpertInfo(labType);
    const storageKey = `k3rn_chat_${labType}_${projectId}`;

    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [input, setInput] = useState("");
    const [isStreaming, setIsStreaming] = useState(false);
    const [streamError, setStreamError] = useState<string | null>(null);
    const [rateLimited, setRateLimited] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    // Load messages from localStorage
    useEffect(() => {
        const stored = localStorage.getItem(storageKey);
        if (stored) {
            try {
                const parsed = JSON.parse(stored);
                if (Array.isArray(parsed) && parsed.length > 0) {
                    setMessages(parsed);
                    return;
                }
            } catch { /* ignore */ }
        }
        // Set welcome message
        setMessages([{ role: "assistant", content: getWelcomeMessage(project, labType) }]);
    }, [storageKey, project, labType]);

    // Save messages to localStorage
    useEffect(() => {
        if (messages.length > 0) {
            localStorage.setItem(storageKey, JSON.stringify(messages));
        }
    }, [messages, storageKey]);

    // Auto-scroll
    useEffect(() => {
        chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages, isStreaming]);

    const sendMessage = useCallback(async () => {
        const text = input.trim();
        if (!text || isStreaming || rateLimited) return;

        setInput("");
        setStreamError(null);

        const userMsg: ChatMessage = { role: "user", content: text };
        const updatedMessages = [...messages, userMsg];
        setMessages(updatedMessages);
        setIsStreaming(true);

        // Build project context
        const projectContext = project ? {
            title: project.title,
            description: project.description,
            globalScore: project.globalScore,
            recommendation: project.recommendation,
            confidenceLevel: project.confidenceLevel,
            axes: project.analysis.axes,
            synthesis: project.analysis.synthesis,
            risks: project.analysis.risks,
            levers: project.fullResult?.levers?.map((l) => ({
                axis: l.axis,
                action: l.action,
                expected_impact: l.expected_impact,
            })),
        } : {
            title: "Projet inconnu",
            description: "",
            globalScore: 0,
            recommendation: "EXPLORE",
            confidenceLevel: "LOW",
            axes: [],
            synthesis: "",
            risks: [],
        };

        try {
            const response = await fetch("/api/expert-chat", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    messages: updatedMessages.filter((m) => m.role === "user" || m.role === "assistant"),
                    projectContext,
                    labType,
                    language: currentLang,
                }),
            });

            if (response.status === 429) {
                setRateLimited(true);
                setStreamError("Limite de requetes atteinte. Reessayez dans quelques instants.");
                setTimeout(() => setRateLimited(false), 30000);
                setIsStreaming(false);
                return;
            }

            if (!response.ok) {
                throw new Error(`Erreur ${response.status}`);
            }

            const reader = response.body?.getReader();
            if (!reader) throw new Error("No reader");

            const decoder = new TextDecoder();
            let assistantContent = "";

            // Add empty assistant message
            setMessages((prev) => [...prev, { role: "assistant", content: "" }]);

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;

                const chunk = decoder.decode(value, { stream: true });
                const lines = chunk.split("\n");

                for (const line of lines) {
                    if (!line.startsWith("data: ")) continue;
                    const data = line.slice(6).trim();
                    if (data === "[DONE]") continue;

                    try {
                        const parsed = JSON.parse(data);
                        if (parsed.error) {
                            if (parsed.error === "rate_limited") {
                                setRateLimited(true);
                                setStreamError("Limite de requetes atteinte.");
                                setTimeout(() => setRateLimited(false), 30000);
                            } else {
                                setStreamError("Erreur de connexion. Le message partiel est conserve.");
                            }
                            break;
                        }
                        if (parsed.text) {
                            assistantContent += parsed.text;
                            setMessages((prev) => {
                                const updated = [...prev];
                                updated[updated.length - 1] = { role: "assistant", content: assistantContent };
                                return updated;
                            });
                        }
                    } catch { /* ignore malformed chunks */ }
                }
            }
        } catch (error: any) {
            setStreamError("Erreur de connexion. Verifiez votre connexion internet.");
            // Keep partial content if any
            setMessages((prev) => {
                const last = prev[prev.length - 1];
                if (last?.role === "assistant" && !last.content) {
                    return prev.slice(0, -1); // Remove empty assistant message
                }
                return prev;
            });
        } finally {
            setIsStreaming(false);
        }
    }, [input, isStreaming, rateLimited, messages, project, labType, currentLang]);

    function handleKeyDown(e: React.KeyboardEvent) {
        if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault();
            sendMessage();
        }
    }

    // Simple markdown-like rendering: bold and line breaks
    function renderContent(content: string) {
        const parts = content.split(/(\*\*[^*]+\*\*)/g);
        return parts.map((part, i) => {
            if (part.startsWith("**") && part.endsWith("**")) {
                return <strong key={i} className="text-white font-semibold">{part.slice(2, -2)}</strong>;
            }
            // Handle line breaks
            return part.split("\n").map((line, j) => (
                <span key={`${i}-${j}`}>
                    {j > 0 && <br />}
                    {line}
                </span>
            ));
        });
    }

    return (
        <aside className="w-96 bg-[#2F323A] border-l border-[#3A3D45] flex flex-col shrink-0 z-20">
            {/* Header */}
            <div className="h-14 px-4 border-b border-[#3A3D45] flex justify-between items-center bg-[#22242B]">
                <div className="flex items-center gap-3">
                    <div className={cn("w-7 h-7 rounded-full flex items-center justify-center text-[10px] text-white font-bold", expert.color)}>
                        {expert.letter}
                    </div>
                    <div className="flex flex-col">
                        <span className="text-xs font-bold text-white">{expert.name}</span>
                        <span className="text-[10px] text-gray-500 uppercase tracking-wider">{expert.role}</span>
                    </div>
                    <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse ml-1" />
                </div>
                <Button variant="ghost" size="icon" className="h-8 w-8 text-gray-400 hover:text-white rounded-full">
                    <Settings className="w-4 h-4" />
                </Button>
            </div>

            {/* Chat Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-[#2F323A]">
                {messages.map((msg, i) => (
                    <div key={i} className={cn(
                        "flex gap-3 animate-in fade-in slide-in-from-bottom-2 duration-300",
                        msg.role === "user" && "flex-row-reverse"
                    )}>
                        {msg.role === "assistant" && (
                            <div className="flex-shrink-0">
                                <div className={cn(
                                    "w-7 h-7 rounded-full flex items-center justify-center text-[10px] text-white font-bold",
                                    expert.color
                                )}>
                                    {expert.letter}
                                </div>
                            </div>
                        )}
                        <div className={cn(
                            "max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed",
                            msg.role === "assistant"
                                ? "bg-[#22242B] border border-white/5 rounded-tl-none text-gray-300"
                                : "bg-[#F75105]/10 border border-[#F75105]/20 rounded-tr-none text-gray-200"
                        )}>
                            {renderContent(msg.content)}
                        </div>
                    </div>
                ))}

                {/* Streaming indicator */}
                {isStreaming && messages[messages.length - 1]?.role === "assistant" && messages[messages.length - 1]?.content === "" && (
                    <div className="flex gap-3">
                        <div className="flex-shrink-0">
                            <div className={cn("w-7 h-7 rounded-full flex items-center justify-center text-[10px] text-white font-bold", expert.color)}>
                                {expert.letter}
                            </div>
                        </div>
                        <div className="p-3 bg-[#22242B] border border-white/5 rounded-2xl rounded-tl-none">
                            <div className="flex gap-1">
                                <div className="w-2 h-2 rounded-full bg-gray-500 animate-bounce" style={{ animationDelay: "0ms" }} />
                                <div className="w-2 h-2 rounded-full bg-gray-500 animate-bounce" style={{ animationDelay: "150ms" }} />
                                <div className="w-2 h-2 rounded-full bg-gray-500 animate-bounce" style={{ animationDelay: "300ms" }} />
                            </div>
                        </div>
                    </div>
                )}

                {/* Stream error */}
                {streamError && (
                    <div className="text-center py-2 px-3 bg-red-500/10 border border-red-500/20 rounded-lg text-xs text-red-400">
                        {streamError}
                    </div>
                )}

                <div ref={chatEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-[#22242B] border-t border-[#3A3D45]">
                <div className="relative flex items-end gap-2">
                    <div className="relative flex-1">
                        <textarea
                            ref={textareaRef}
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={handleKeyDown}
                            placeholder={rateLimited ? "Patientez..." : (t.workspace.chat.replyPlaceholder || "Repondre...")}
                            disabled={rateLimited}
                            rows={1}
                            className="w-full pl-4 pr-12 py-3 bg-[#2F323A] border border-transparent rounded-[var(--radius-md)] text-sm text-white placeholder:text-gray-500 focus:outline-none focus:border-[#F75105]/50 focus:bg-[#1a1c22] transition-all resize-none disabled:opacity-50"
                            style={{ minHeight: "44px", maxHeight: "120px" }}
                        />
                        <button
                            onClick={sendMessage}
                            disabled={!input.trim() || isStreaming || rateLimited}
                            className="absolute right-2 bottom-2 p-1.5 bg-[#F75105] hover:bg-[#F78E21] text-white rounded-lg transition-all active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed"
                        >
                            <Send className="w-3.5 h-3.5" />
                        </button>
                    </div>
                </div>
                {isStreaming && (
                    <div className="mt-2 text-[10px] text-gray-500 flex items-center gap-1">
                        <div className="w-1.5 h-1.5 rounded-full bg-[#F75105] animate-pulse" />
                        {expert.name} est en train d&apos;ecrire...
                    </div>
                )}
            </div>
        </aside>
    );
}

