"use client";

import { useParams } from "next/navigation";
import { useProject } from "@/hooks/use-project";
import { DiscoveryPanel } from "@/components/workspace/lab1/discovery-panel";
import { DiscoveryWorkspace } from "@/components/workspace/lab1/discovery-workspace";
import { ExpertChat } from "@/components/workspace/expert-chat";
import { WorkspaceHeader } from "@/components/workspace/header";

export default function Lab1DiscoveryPage() {
    const params = useParams();
    const id = params.id as string;
    const { project, isLoading } = useProject(id);

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-screen bg-[#22242B] text-white">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-8 h-8 border-2 border-[#F75105] border-t-transparent rounded-full animate-spin" />
                    <span className="text-sm text-gray-400">Chargement du projet...</span>
                </div>
            </div>
        );
    }

    if (!project) {
        return (
            <div className="flex items-center justify-center h-screen bg-[#22242B] text-white">
                <div className="flex flex-col items-center gap-4 text-center">
                    <div className="text-4xl">?</div>
                    <h2 className="text-lg font-medium">Projet introuvable</h2>
                    <p className="text-sm text-gray-400 max-w-sm">
                        Le projet avec l&apos;ID <code className="text-[#F75105]">{id}</code> n&apos;a pas ete trouve dans votre espace de travail.
                    </p>
                    <a href="/workspace" className="text-sm text-[#F75105] hover:text-[#F78E21] transition-colors">
                        Retour au workspace
                    </a>
                </div>
            </div>
        );
